script.code:
let allData = {{workflowparams:allData}}
const updatedSA = []
const saveAs = {{workflowparams:saveAs}}

// Helper function to format qty and price fields to 3 decimal places
const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(3);
};

for (const [index, saLineItem] of allData.stock_adjustment.entries()) {
  saLineItem.unit_price = formatNumber(saLineItem.unit_price);

  saLineItem.plant_id = allData.plant_id || null;
  saLineItem.line_index = index + 1;

  updatedSA.push(saLineItem)
}

allData.stock_adjustment = updatedSA

if ({{workflowparams:pageStatus}} === "Add") {
  allData.stock_adjustment_status = "Draft"
}

if (saveAs === "Draft") {
  if(allData.adjustment_no_type !== -9999 && (
  !allData.adjustment_no || allData.adjustment_no === null || allData.adjustment_no === ''
)) {
  allData.adjustment_no = 'draft'
  }
} else {
  if (
  allData.adjustment_no_type !== -9999 &&
  (!allData.adjustment_no ||
    allData.adjustment_no === null ||
    allData.adjustment_no === "" ||
    allData.stock_adjustment_status !== "In Progress")
) {
  allData.adjustment_no = 'issued'
  }
}

if (allData.acc_integration_type !== "No Accounting Integration") {
  allData.posted_status = "Unposted";
} else {
  allData.posted_status = "";
}

return {
  allData: allData,
  stock_adjustment_status: allData.stock_adjustment_status,
  stock_count_id: allData.stock_count_id || null,
}

return {
  required_fields: JSON.stringify([
      { name: "adjustment_date", label: "Adjustment Date" },
      { name: "adjustment_type", label: "Adjustment Type" },
      { name: "plant_id", label: "Plant" },
      {
        name: "stock_adjustment",
        label: "Stock Adjustment Details",
        isArray: true,
        arrayType: "object",
        arrayFields: [],
      },
    ]),
  data: JSON.stringify({
    adjustment_date: {{node:code_node_O4tWJ5JH.data.allData.adjustment_date}},
    adjustment_type: {{node:code_node_O4tWJ5JH.data.allData.adjustment_type}},
    plant_id: {{node:code_node_O4tWJ5JH.data.allData.plant_id}},
    stock_adjustment: {{node:code_node_O4tWJ5JH.data.allData.stock_adjustment}},
  })
}

const page_status = {{workflowparams:pageStatus}};
const stock_adjustment_status = {{node:code_node_O4tWJ5JH.data.stock_adjustment_status}}
let allData;

if (page_status === "Add") {
  const rawData = {{node:add_node_Yk7ukSPp.data}}
  allData = Array.isArray(rawData) ? rawData[0] : rawData;
} else if (page_status === "Edit" && stock_adjustment_status === "Draft") {
  allData = {{node:get_node_Rs3nGg9f.data.data}}
} else {
  allData = {{node:code_node_O4tWJ5JH.data.allData}}
}

const subformData = allData.stock_adjustment;
const currentIndexRaw = {{node:get_cache_node_1kgmpCTb.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;

const plant_id = allData.plant_id;
const organization_id = allData.organization_id;
const stock_adjustment_no = allData.adjustment_no;
const doc_date = allData.adjustment_date;

const item = subformData[index];
const material_id = item.material_id;
const material_uom = item.uom_id || "";
const total_quantity = item.total_quantity;
const remark = item.item_remark || null;
const remark2 = item.item_remark2 || null;
const remark3 = item.item_remark3 || null;
const inventory_category = item.item_category || "Unrestricted";
const unit_price = item.unit_price || 0;

let tempDataParsed;

const tempData = item.balance_index;
if (!tempData) {
  tempDataParsed = [];
} else {
  tempDataParsed = JSON.parse(tempData);
  tempDataParsed = tempDataParsed.filter(
    (tempData) => tempData.sa_quantity > 0
  );
  if (!Array.isArray(tempDataParsed)) {
    tempDataParsed = [];
  }
}

return {
  plant_id: plant_id,
  organization_id: organization_id,
  stock_adjustment_no: stock_adjustment_no,
  page_status: page_status,
  material_id: material_id,
  material_uom: material_uom,
  total_quantity: total_quantity,
  unit_price: unit_price,
  inventory_category: inventory_category,
  doc_date: doc_date,
  remark: remark,
  remark2: remark2,
  remark3: remark3,
  balancesToProcess: tempDataParsed,
  index: index,
  nextIndex: index + 1
};

const balancesToProcess = {{node:code_node_qrsgEz2F.data.balancesToProcess}}
const currentIndexRaw = {{node:get_cache_node_EWeoHeKF.data}}
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0
const saveAs = {{workflowparams:saveAs}}

const balance = balancesToProcess[index];
const batch_id = balance.batch_id || null;
const location_id = balance.location_id;
const quantity = balance.sa_quantity;
let inventory_category = balance.category || "Unrestricted";
const manufacturing_date = balance.manufacturing_date || null;
const expired_date = balance.expired_date || null;
const movement_type = balance.movement_type.toLowerCase();

return {
  batch_id: batch_id,
  location_id: location_id,
  quantity: quantity,
  inventory_category: inventory_category,
  manufacturing_date: manufacturing_date,
  expired_date: expired_date,
  movement_type: movement_type,
  index: index,
  nextIndex: index + 1
};

const scData = {{node:get_node_jN1E0Ycx.data.data}};
const table_stock_count = scData.table_stock_count;

const totalData = table_stock_count.length;
const AdjustedData = table_stock_count.filter((item) => item.line_status === "Adjusted")
const totalAdjusted = AdjustedData.length;

let adjustmentStatus
if (totalData === totalAdjusted) {
  adjustmentStatus = "Fully Adjusted"
} else {
  adjustmentStatus = "Partially Adjusted"
}

return {
  adjustmentStatus
}

const tableSA = {{node:code_node_O4tWJ5JH.data.allData.stock_adjustment}}

const uniqueItemIds = [
  ...new Set(
    tableSA
      .filter((item) => item.material_id)
      .map((item) => item.material_id),
  ),
];

const date = new Date().toISOString();
const updates = [];

for (const itemId of uniqueItemIds) {
  updates.push({
    id: itemId,
    last_transaction_date: date,
  });
}

return {
  updates: updates,
};
